        int maxChar = 'a';
        for (int i = 0; i < s.length(); i++) {
            if (s.charAt(i) > maxChar) {
                maxChar = s.charAt(i);
            }
        }
        int firstIndex = -1;
        for (int i = 0; i < s.length(); i++) {
            if (s.charAt(i) == maxChar) {
                firstIndex = i;
